INSERT INTO public.biomarkers_library (biomarker_name, biomarker_code, category, description, unit_of_measurement, normal_range_male, normal_range_female, clinical_significance, related_conditions, lifestyle_factors, interpretation_guide) VALUES
-- THYROID
('Free T4', 'FT4', 'Thyroid', 'Free T4 (thyroxine) is the main circulating thyroid hormone not bound to proteins, produced by the thyroid gland and converted to the more active T3 in tissues.', 'pmol/L', '12–22 pmol/L', '12–22 pmol/L', 'Low FT4 with high TSH suggests primary hypothyroidism; high FT4 with low TSH indicates hyperthyroidism. Key marker for thyroid function assessment.', ARRAY['Hypothyroidism','Hyperthyroidism','Graves'' disease','Hashimoto''s thyroiditis','Pituitary disorders'], ARRAY['Thyroid medication adherence','Iodine intake','Stress management'], '{"low":{"meaning":"Low FT4 with high TSH usually suggests primary hypothyroidism, often from autoimmune thyroiditis or previous thyroid treatment. Low FT4 with low or normal TSH may point to pituitary or hypothalamic problems.","symptoms":"Tiredness, weight gain, feeling cold, dry skin, constipation."},"high":{"meaning":"High FT4 with low TSH usually indicates hyperthyroidism from Graves'' disease, over-replacement with thyroid hormone or thyroid nodules.","symptoms":"Weight loss, heat intolerance, anxiety, palpitations, tremor."},"urgent":"Seek urgent help for chest pain, severe palpitations, shortness of breath or confusion with abnormal thyroid results.","improvement":"Treatment aims to normalise thyroid hormone levels using levothyroxine for hypothyroidism or anti-thyroid drugs, radioiodine or surgery for hyperthyroidism under endocrinology guidance."}'::jsonb),

('Free T3', 'FT3', 'Thyroid', 'Free T3 (triiodothyronine) is the active thyroid hormone produced by the thyroid and by conversion from T4 in tissues, driving metabolic effects such as heart rate and temperature regulation.', 'pmol/L', '3.1–6.8 pmol/L', '3.1–6.8 pmol/L', 'High FT3 with low TSH is seen in hyperthyroidism; low FT3 can occur during serious illness or hypothyroidism.', ARRAY['Hyperthyroidism','T3 toxicosis','Non-thyroidal illness','Hypothyroidism'], ARRAY['Thyroid medication compliance','Stress reduction','Adequate nutrition'], '{"low":{"meaning":"Low FT3 with low or normal FT4 can occur during serious illness (non-thyroidal illness) or in hypothyroidism.","symptoms":"Fatigue, cold intolerance, weight gain."},"high":{"meaning":"High FT3 with low TSH is seen in hyperthyroidism and sometimes in T3-toxicosis where FT4 is normal but FT3 is high.","symptoms":"Palpitations, anxiety, heat intolerance, weight loss."},"urgent":"Severe palpitations, chest pain or breathlessness with high FT3 need urgent evaluation.","improvement":"Management is via standard hyper- or hypothyroidism treatment, chosen by an endocrinologist and monitored with repeat thyroid function tests."}'::jsonb),

('Total T4', 'TT4', 'Thyroid', 'Total T4 measures both protein-bound and free thyroxine in the blood, reflecting overall T4 levels which can be influenced by binding protein changes.', 'nmol/L', 'Lab-specific', 'Lab-specific', 'Useful alongside FT4 and TSH; binding-protein changes (pregnancy, oestrogen therapy) can alter total T4 without true thyroid dysfunction.', ARRAY['Hypothyroidism','Hyperthyroidism','Pregnancy-related thyroid changes','Oestrogen therapy effects'], ARRAY['Medication review','Hormonal status awareness'], '{"low":{"meaning":"Low total T4 may indicate hypothyroidism but can also occur with low binding proteins or serious illness. FT4 and TSH are usually more informative.","symptoms":"Fatigue, weight gain, cold sensitivity."},"high":{"meaning":"High total T4 may reflect hyperthyroidism or raised binding proteins (e.g. pregnancy, oestrogen therapy).","symptoms":"Weight loss, tremor, heat intolerance."},"urgent":"Acute severe thyroid symptoms should prompt urgent assessment regardless of which thyroid test is abnormal.","improvement":"Optimising thyroid treatment or addressing factors that alter binding proteins is guided by a clinician using the full thyroid panel."}'::jsonb),

('Total T3', 'TT3', 'Thyroid', 'Total T3 measures all triiodothyronine in the blood including free and protein-bound hormone, especially useful when hyperthyroidism is suspected.', 'nmol/L', 'Lab-specific', 'Lab-specific', 'High T3 with low TSH is typical of hyperthyroidism; low T3 is common in non-thyroidal illness.', ARRAY['Hyperthyroidism','T3-predominant thyrotoxicosis','Non-thyroidal illness','Hypothyroidism'], ARRAY['Thyroid treatment compliance','Nutrition during illness'], '{"low":{"meaning":"Low T3 is common in non-thyroidal illness and advanced hypothyroidism. Must be interpreted carefully in unwell patients.","symptoms":"Fatigue, weakness."},"high":{"meaning":"High T3 with low TSH is typical of hyperthyroidism and T3-predominant disease.","symptoms":"Palpitations, anxiety, weight loss, heat intolerance."},"urgent":"Severe hyperthyroid symptoms (chest pain, severe breathlessness, mental status changes) are emergencies.","improvement":"Definitive management is via standard thyroid disease treatment; lifestyle alone cannot normalise significant T3 abnormalities."}'::jsonb),

('Thyroid Peroxidase Antibodies', 'TPOAB', 'Thyroid', 'TPO antibodies are immune proteins directed against thyroid peroxidase, an enzyme involved in thyroid hormone production, used to diagnose autoimmune thyroid disease.', 'IU/mL', 'Negative or below lab cut-off', 'Negative or below lab cut-off', 'High levels are common in Hashimoto''s thyroiditis and Graves'' disease and increase the risk of developing hypothyroidism over time.', ARRAY['Hashimoto''s thyroiditis','Graves'' disease','Autoimmune thyroid disease','Hypothyroidism risk'], ARRAY['Regular thyroid monitoring','Stress management','Selenium intake may support thyroid health'], '{"low":{"meaning":"Low or negative TPOAb makes autoimmune thyroid disease less likely but does not completely exclude it.","symptoms":"Usually none."},"high":{"meaning":"Raised TPOAb suggest autoimmune thyroiditis and increase the risk of developing hypothyroidism over time. Some people with high antibodies have normal thyroid function initially.","symptoms":"May have no symptoms initially; over time may develop hypothyroid symptoms."},"urgent":"TPOAb levels themselves are not an emergency; urgency depends on thyroid hormone levels and symptoms.","improvement":"There is no direct way to lower antibodies, but regular monitoring of TSH and FT4, prompt treatment of hypothyroidism, and managing other autoimmune conditions are key."}'::jsonb),

('Thyroglobulin Antibodies', 'TGAB', 'Thyroid', 'Tg antibodies target thyroglobulin, a protein used to make thyroid hormones, and are another marker of autoimmune thyroid disease.', 'IU/mL', 'Negative or below lab cut-off', 'Negative or below lab cut-off', 'Often present in autoimmune thyroiditis; can interfere with thyroglobulin measurement in thyroid cancer follow-up.', ARRAY['Autoimmune thyroiditis','Thyroid cancer monitoring','Hashimoto''s thyroiditis'], ARRAY['Regular thyroid monitoring','Balanced iodine intake'], '{"low":{"meaning":"Negative TgAb reduces the likelihood of autoimmune thyroid disease but must be considered with TPOAb and thyroid function tests.","symptoms":"Usually none."},"high":{"meaning":"High TgAb often accompany autoimmune thyroiditis and can affect monitoring in thyroid cancer follow-up where thyroglobulin is used as a tumour marker.","symptoms":"Variable; depends on thyroid function status."},"urgent":"Abnormal antibody levels alone do not require urgent care; acute thyroid symptoms do.","improvement":"Management focuses on monitoring and treating thyroid dysfunction and, in cancer follow-up, using appropriate tests and imaging as advised by specialists."}'::jsonb),

('Thyroglobulin', 'TG', 'Thyroid', 'Thyroglobulin is a protein made by thyroid cells, mainly used as a tumour marker after thyroid cancer treatment to detect recurrence.', 'µg/L', 'Lab-specific; very low after thyroidectomy', 'Lab-specific; very low after thyroidectomy', 'After thyroid removal for cancer, thyroglobulin should be very low; rising levels can suggest recurrence.', ARRAY['Thyroid cancer','Thyroid cancer recurrence','Post-thyroidectomy monitoring'], ARRAY['Adherence to follow-up appointments','Thyroid hormone replacement compliance'], '{"low":{"meaning":"Low levels after thyroid removal are reassuring and expected.","symptoms":"None expected."},"high":{"meaning":"High or rising thyroglobulin after treatment can indicate residual or recurrent thyroid tissue or cancer. TgAb can interfere with interpretation.","symptoms":"May have no symptoms; neck swelling or other changes possible."},"urgent":"Any sudden neck swelling, breathing difficulty or rapid symptom change needs urgent assessment.","improvement":"Only a specialist should adjust investigations or treatment (e.g. imaging, radioiodine, surgery) based on thyroglobulin trends."}'::jsonb),

-- HORMONES
('Oestradiol', 'E2', 'Hormones', 'Oestradiol is the main form of oestrogen in women of reproductive age, produced mainly by the ovaries, supporting menstrual cycles, bone health and many body systems.', 'pmol/L', 'Lab-specific (lower in males)', 'Varies by cycle phase and menopausal status', 'Key reproductive hormone; low levels associated with menopause and bone loss, high levels with ovarian cysts or tumours.', ARRAY['Menopause','Ovarian insufficiency','PCOS','Osteoporosis','Ovarian cysts'], ARRAY['Healthy body weight','Regular exercise','Adequate calcium and vitamin D','Hormone therapy adherence'], '{"low":{"meaning":"Low oestradiol can occur with menopause, ovarian insufficiency, very low body weight, chronic illness or certain medications.","symptoms":"Hot flushes, irregular or absent periods, low bone density, vaginal dryness."},"high":{"meaning":"High oestradiol may be seen with ovarian cysts, certain tumours, high-dose hormone therapy or obesity.","symptoms":"Breast tenderness, bloating, mood changes."},"urgent":"Sudden severe pelvic pain, heavy bleeding or symptoms of blood clots (leg swelling, chest pain, breathlessness) require urgent care.","improvement":"Management includes addressing underlying causes and, where appropriate, using hormone therapy or adjusting treatment under specialist guidance."}'::jsonb),

('Progesterone', 'PROG', 'Hormones', 'Progesterone is produced mainly after ovulation, preparing the womb lining for implantation and supporting early pregnancy.', 'nmol/L', 'Low (typically < 5 nmol/L)', 'Varies by cycle phase; mid-luteal > 30 nmol/L suggests ovulation', 'Used to confirm ovulation; low mid-luteal progesterone may indicate anovulation.', ARRAY['Anovulation','Infertility','Luteal phase deficiency','Miscarriage risk','PCOS'], ARRAY['Stress reduction','Healthy body weight','Regular sleep patterns'], '{"low":{"meaning":"Low mid-luteal progesterone may indicate anovulation (no ovulation) or irregular cycles.","symptoms":"Irregular periods, difficulty conceiving."},"high":{"meaning":"High progesterone is normal in pregnancy or when taking progesterone medication.","symptoms":"Breast tenderness, bloating, drowsiness in some cases."},"urgent":"Heavy bleeding, severe pelvic pain or early-pregnancy concerns need urgent assessment.","improvement":"Treatment depends on fertility goals and underlying conditions; options may include lifestyle measures, ovulation-inducing medicines or progesterone therapy as advised by a specialist."}'::jsonb),

('Total Testosterone', 'TT', 'Hormones', 'Total testosterone is the main androgen in men and is present in women in lower amounts, supporting sexual function, muscle mass, bone health and mood.', 'nmol/L', '8.6–29 nmol/L (morning sample)', '0.3–1.7 nmol/L', 'Low testosterone in men causes reduced libido, erectile difficulties and low energy; high testosterone in women may indicate PCOS.', ARRAY['Hypogonadism','PCOS','Pituitary disorders','Obesity-related low testosterone','Klinefelter syndrome'], ARRAY['Weight management','Adequate sleep','Limiting alcohol','Regular exercise','Stress reduction'], '{"low":{"meaning":"Low testosterone in men can cause reduced libido, erectile difficulties, low energy, loss of muscle and low mood. Causes include testicular disease, pituitary problems, obesity and certain medications.","symptoms":"Reduced libido, erectile dysfunction, fatigue, loss of muscle mass, low mood."},"high":{"meaning":"High testosterone in women may cause acne, excess hair growth and menstrual irregularities, often associated with PCOS.","symptoms":"Acne, hirsutism, irregular periods, deepening voice (in women)."},"urgent":"Sudden visual changes, severe headaches or other signs of pituitary disease require urgent review.","improvement":"Lifestyle changes (weight management, sleep, limiting alcohol) can help borderline cases. Hormone therapy should only be started after specialist assessment."}'::jsonb),

('Free Testosterone', 'FT', 'Hormones', 'Free testosterone reflects the biologically active portion of testosterone not bound strongly to proteins, acting directly on tissues.', 'pmol/L', 'Lab-specific', 'Lab-specific', 'May better explain symptoms in men with borderline total testosterone and high SHBG; high free testosterone in women is often associated with PCOS.', ARRAY['Hypogonadism','PCOS','SHBG abnormalities','Insulin resistance'], ARRAY['Weight management','Exercise','Managing insulin resistance'], '{"low":{"meaning":"Low free testosterone may better explain symptoms in men with borderline total testosterone and high SHBG.","symptoms":"Similar to low total testosterone: fatigue, low libido, reduced muscle mass."},"high":{"meaning":"High free testosterone in women is often associated with PCOS and hyperandrogenic symptoms.","symptoms":"Acne, excess hair growth, irregular periods."},"urgent":"Urgent symptoms of pituitary or adrenal disease require prompt assessment.","improvement":"Management targets underlying causes, including weight reduction, managing insulin resistance, and specific hormone treatments prescribed by a specialist."}'::jsonb),

('SHBG', 'SHBG', 'Hormones', 'Sex hormone-binding globulin is a protein produced mainly in the liver that binds testosterone and oestrogen, affecting how much hormone is available to tissues.', 'nmol/L', '18–54 nmol/L', '26–110 nmol/L', 'Low SHBG is associated with obesity and insulin resistance; high SHBG with hyperthyroidism, liver disease and oestrogen therapy.', ARRAY['Insulin resistance','Type 2 diabetes','PCOS','Hyperthyroidism','Liver disease'], ARRAY['Weight management','Improving insulin sensitivity','Balanced diet','Exercise'], '{"low":{"meaning":"Low SHBG is associated with obesity, insulin resistance, type 2 diabetes and androgen excess.","symptoms":"May contribute to symptoms of androgen excess."},"high":{"meaning":"High SHBG can be seen with hyperthyroidism, liver disease, oestrogen therapy and some genetic patterns.","symptoms":"May contribute to symptoms of low free testosterone despite normal total levels."},"urgent":"Abnormal SHBG alone is not an emergency; acute symptoms drive urgency.","improvement":"Weight loss, improving insulin sensitivity and managing thyroid or liver disease can help normalise SHBG."}'::jsonb),

('Luteinising Hormone', 'LH', 'Hormones', 'LH is a pituitary hormone that triggers ovulation in women and stimulates testosterone production in men.', 'IU/L', '1.7–8.6 IU/L', 'Varies by cycle phase; mid-cycle surge 6–70 IU/L', 'High LH with high FSH suggests ovarian failure or menopause; disproportionately raised LH may indicate PCOS.', ARRAY['PCOS','Ovarian failure','Menopause','Primary testicular failure','Pituitary disorders'], ARRAY['Stress management','Healthy body weight','Regular exercise'], '{"low":{"meaning":"Low LH can indicate pituitary or hypothalamic problems, excessive exercise, stress or certain chronic illnesses.","symptoms":"Irregular or absent periods, reduced fertility."},"high":{"meaning":"High LH with high FSH suggests ovarian failure or menopause; high LH with low testosterone suggests primary testicular failure. In PCOS, LH may be disproportionately raised.","symptoms":"Irregular periods, hot flushes, reduced fertility."},"urgent":"Urgent concerns relate to pituitary tumours or severe endocrine symptoms and should be evaluated promptly.","improvement":"Management depends on fertility goals and the underlying cause and may involve lifestyle changes, hormone therapy or fertility treatments."}'::jsonb),

('Follicle-Stimulating Hormone', 'FSH', 'Hormones', 'FSH helps control egg development and ovulation in women and sperm production in men, produced by the pituitary gland.', 'IU/L', '1.5–12.4 IU/L', 'Varies by cycle phase; post-menopausal > 25 IU/L', 'High FSH with low oestradiol suggests ovarian failure; low FSH may indicate pituitary disease.', ARRAY['Ovarian failure','Menopause','Primary testicular failure','Hypothalamic amenorrhoea','Pituitary disorders'], ARRAY['Healthy body weight','Balanced nutrition','Stress management','Regular exercise'], '{"low":{"meaning":"Low FSH suggests reduced pituitary drive and may occur in hypothalamic amenorrhoea, pituitary disease or high prolactin.","symptoms":"Absent or irregular periods, reduced fertility."},"high":{"meaning":"High FSH with low oestradiol suggests ovarian failure or menopause; high FSH with low sperm counts may point to primary testicular failure.","symptoms":"Hot flushes, irregular periods, infertility."},"urgent":"Visual symptoms, severe headaches or other pituitary signs need urgent evaluation.","improvement":"Treatment focuses on underlying causes and reproductive goals, including lifestyle interventions, hormone therapy or assisted reproduction."}'::jsonb),

('Prolactin', 'PRL', 'Hormones', 'Prolactin is a pituitary hormone mainly involved in breast development and milk production, normally rising in pregnancy and breastfeeding.', 'mIU/L', '86–324 mIU/L', '102–496 mIU/L', 'High prolactin can cause absent periods, reduced libido and milk leakage; may indicate pituitary tumour.', ARRAY['Prolactinoma','Hyperprolactinaemia','Pituitary tumours','Medication side effects','Infertility'], ARRAY['Medication review','Stress management','Regular sleep'], '{"low":{"meaning":"Low levels are usually not clinically important outside specific pituitary conditions.","symptoms":"Usually none."},"high":{"meaning":"High prolactin can cause absent or irregular periods, reduced libido and milk leakage from the breasts. Causes include medications, stress, pregnancy and prolactin-secreting pituitary tumours.","symptoms":"Irregular or absent periods, galactorrhoea, reduced libido, headaches."},"urgent":"Headaches, visual changes or neurological symptoms with high prolactin require urgent specialist review.","improvement":"Treatment may involve adjusting medications, dopamine-agonist therapy or pituitary surgery in selected cases."}'::jsonb),

('DHEA-S', 'DHEAS', 'Hormones', 'DHEA-S is an adrenal androgen precursor produced mainly by the adrenal glands, which can be converted into other androgens and oestrogens.', 'µmol/L', 'Age-dependent; declines with age', 'Age-dependent; declines with age', 'High DHEA-S can be associated with PCOS, adrenal tumours or congenital adrenal hyperplasia; low levels may indicate adrenal insufficiency.', ARRAY['PCOS','Adrenal tumours','Congenital adrenal hyperplasia','Adrenal insufficiency','Premature adrenarche'], ARRAY['Stress management','Healthy weight','Avoid unnecessary DHEA supplements'], '{"low":{"meaning":"Low DHEA-S may be seen in adrenal insufficiency or with ageing.","symptoms":"Fatigue, reduced wellbeing."},"high":{"meaning":"High levels can be associated with PCOS, adrenal tumours or congenital adrenal hyperplasia and may cause acne, hirsutism and menstrual irregularities.","symptoms":"Acne, excess hair growth, irregular periods, virilisation signs."},"urgent":"Virilisation signs or symptoms of adrenal crisis require urgent care.","improvement":"Management depends on the cause and may involve imaging, endocrine therapy or surgery under specialist care."}'::jsonb),

('Cortisol (Morning)', 'CORT', 'Hormones', 'Morning cortisol is produced by the adrenal glands following a daily rhythm, peaking in the early morning, helping regulate metabolism, blood pressure and stress responses.', 'nmol/L', '166–507 nmol/L (morning)', '166–507 nmol/L (morning)', 'Low cortisol may indicate adrenal insufficiency; high cortisol may be seen in Cushing''s syndrome, stress or steroid medication use.', ARRAY['Adrenal insufficiency','Cushing''s syndrome','Addison''s disease','Steroid medication effects','Chronic stress'], ARRAY['Stress management','Regular sleep schedule','Balanced nutrition','Exercise moderation'], '{"low":{"meaning":"Low cortisol may indicate adrenal insufficiency or pituitary ACTH deficiency and can cause fatigue, weight loss, abdominal pain and low blood pressure.","symptoms":"Fatigue, weight loss, dizziness, abdominal pain, low blood pressure."},"high":{"meaning":"High cortisol may be seen in Cushing''s syndrome, stress, depression, alcoholism or with steroid medications.","symptoms":"Weight gain (particularly central), thin skin, easy bruising, high blood pressure, mood changes."},"urgent":"Symptoms of adrenal crisis (severe weakness, vomiting, low blood pressure, collapse) are a medical emergency.","improvement":"Treatment for adrenal insufficiency involves steroid replacement; high cortisol from Cushing''s requires specialist investigation and treatment."}'::jsonb),

-- MINERALS
('Zinc', 'ZN', 'Minerals', 'Zinc is a trace mineral important for immunity, wound healing, taste, smell and skin health, supporting over 300 enzyme reactions in the body.', 'µmol/L', '11–23 µmol/L', '11–23 µmol/L', 'Low zinc impairs immunity and wound healing; high zinc from supplementation can interfere with copper balance.', ARRAY['Zinc deficiency','Impaired immunity','Poor wound healing','Acrodermatitis enteropathica','Copper deficiency (from excess zinc)'], ARRAY['Diet rich in meat, shellfish, nuts and seeds','Appropriate supplementation under guidance','Avoiding excessive zinc supplements'], '{"low":{"meaning":"Low zinc may arise from poor intake, malabsorption, chronic illness or high losses.","symptoms":"Poor wound healing, hair loss, taste changes, frequent infections."},"high":{"meaning":"High zinc is usually due to supplementation and can interfere with copper balance.","symptoms":"Nausea, vomiting, copper deficiency signs."},"urgent":"Severe gastrointestinal symptoms, confusion or other acute illness with suspected overdose need urgent care.","improvement":"Dietary changes (more meat, shellfish, dairy, nuts, seeds and whole grains) and appropriately dosed supplements under medical guidance can correct deficiency."}'::jsonb),

('Magnesium', 'MG', 'Minerals', 'Magnesium is a mineral involved in muscle, nerve and heart function, acting as a cofactor in hundreds of biochemical reactions.', 'mmol/L', '0.7–1.0 mmol/L', '0.7–1.0 mmol/L', 'Low magnesium can cause muscle cramps, weakness and heart rhythm disturbances; high magnesium usually from kidney failure or excess supplements.', ARRAY['Hypomagnesaemia','Cardiac arrhythmias','Muscle cramps','Kidney disease','Alcoholism'], ARRAY['Diet rich in green leafy vegetables, nuts, seeds and whole grains','Moderate alcohol intake','Appropriate supplementation','Medication review (diuretics)'], '{"low":{"meaning":"Low magnesium can occur with poor intake, alcoholism, diuretics, diarrhoea or certain drugs.","symptoms":"Muscle cramps, weakness, tremor, abnormal heart rhythms."},"high":{"meaning":"High magnesium usually results from kidney failure or excessive supplements and can cause low blood pressure, drowsiness and cardiac problems.","symptoms":"Drowsiness, low blood pressure, nausea, breathing difficulty."},"urgent":"Severe weakness, breathing difficulty or heart rhythm changes with abnormal magnesium require urgent treatment.","improvement":"Diet rich in green leafy vegetables, nuts, seeds and whole grains plus supplements where appropriate can restore levels; high magnesium needs medical management and review of supplements and kidney function."}'::jsonb),

('Selenium', 'SE', 'Minerals', 'Selenium is a trace element important for antioxidant enzymes and thyroid function, forming part of selenoproteins that protect cells from oxidative damage.', 'µg/L', '70–150 µg/L', '70–150 µg/L', 'Low selenium may impair thyroid function and antioxidant defence; high selenium (selenosis) causes hair loss, nail changes and neurological symptoms.', ARRAY['Selenium deficiency','Thyroid dysfunction','Keshan disease','Selenosis (toxicity)','Oxidative stress'], ARRAY['Dietary sources: Brazil nuts, seafood, meat','Cautious supplementation to avoid overdose','Balanced diet'], '{"low":{"meaning":"Low selenium may occur with poor dietary intake, gastrointestinal disease or certain regions with low soil selenium.","symptoms":"Fatigue, muscle weakness, impaired immunity, thyroid dysfunction."},"high":{"meaning":"High selenium (selenosis) is usually due to excessive supplementation and can cause hair loss, nail changes, gastrointestinal upset and neurological symptoms.","symptoms":"Hair loss, nail brittleness, garlic breath, nausea, neurological symptoms."},"urgent":"Suspected selenium toxicity with neurological symptoms or severe gastrointestinal upset needs urgent care.","improvement":"Dietary sources include Brazil nuts (very rich), seafood and meat; supplementation should be cautious and supervised to avoid overdose."}'::jsonb);